type ModalType = 'wechat' | 'qq' | null;

export function SocialLinks() {
  const [showModal, setShowModal] = useState<ModalType>(null);

  const modalConfig = {
    wechat: {
      title: '微信扫码',
      image: '/images/wx.jpg',
      alt: '微信二维码',
    },
    qq: {
      title: 'QQ扫码',
      image: '/images/QQ.jpg',
      alt: 'QQ二维码',
    },
  };

  return (
    <>
      <div className="flex gap-4" style={{ marginBottom: '103px' }}>
        {siteConfig.social.map((s) => (
          s.name === "微信" || s.name === "QQ" ? (
            <button
              key={s.name}
              onClick={() => setShowModal(s.name === "微信" ? 'wechat' : 'qq')}
              className="p-3 rounded-full border border-white/30 text-white hover:border-white hover:bg-white/20 hover:scale-110 hover:shadow-lg hover:shadow-white/20 transition-all duration-300"
              title={s.name}
            >
              <SocialIcon name={s.icon} />
            </button>
          ) : (
            <a
              key={s.name}
              href={s.url}
              target="_blank"
              rel="noopener noreferrer"
              className="p-3 rounded-full border border-white/30 text-white hover:border-white hover:bg-white/20 hover:scale-110 hover:shadow-lg hover:shadow-white/20 transition-all duration-300"
              title={s.name}
            >
              <SocialIcon name={s.icon} />
            </a>
          )
        ))}
      </div>

      {/* QR Code Modal */}
      {showModal && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm"
          onClick={() => setShowModal(null)}
        >
          <div
            className="relative bg-white dark:bg-gray-900 rounded-2xl p-6 shadow-2xl max-w-sm mx-4"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => setShowModal(null)}
              className="absolute -top-3 -right-3 w-8 h-8 bg-gray-800 hover:bg-gray-700 text-white rounded-full flex items-center justify-center transition-colors"
            >
              ✕
            </button>
            <h3 className="text-lg font-semibold mb-4 text-center text-gray-900 dark:text-white">
              {modalConfig[showModal].title}
            </h3>
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={modalConfig[showModal].image}
              alt={modalConfig[showModal].alt}
              className="w-64 h-64 object-contain rounded-lg"
            />
          </div>
        </div>
      )}
    </>
  );
}
